    g.perform_action(GameAction::CastSpell {
        card_id: po,
        target: Some(Target::Permanent(bear2)),
        additional_targets: vec![],
        mode: Some(1),
        x_value: None,
    })
    .expect("Practiced Offense castable for {2}{W}");
    drain_stack(&mut g);

    let bear2_card = g.battlefield_find(bear2).unwrap();
