    let fractal_id = g.battlefield.iter()
        .find(|c| c.controller == 0
            && c.definition.subtypes.creature_types.contains(&CreatureType::Fractal))
        .map(|c| c.id).unwrap();
    let fractal = g.compute_battlefield().into_iter().find(|c| c.id == fractal_id).unwrap();
