    let es = g.add_card_to_hand(0, catalog::silverquill_edict_speaker_b135());
    g.players[0].mana_pool.add(Color::White, 1);
    g.players[0].mana_pool.add(Color::Black, 1);
    g.players[0].mana_pool.add_colorless(1);
